// Resolver o os_id real (interno Bom Saldo = 7+ dígitos)
const trigger = $('Trigger').first().json;
const supabase = $input.first().json;

// Prioridade: os_id_bomsaldo do Supabase > os_id do trigger
const osIdSupa = String(supabase.os_id_bomsaldo || '').replace(/[^0-9]/g, '');
const osIdTrigger = String(trigger.os_id || '').replace(/[^0-9]/g, '');

let osIdReal;
if (osIdSupa.length >= 7) {
  osIdReal = osIdSupa;
} else if (osIdTrigger.length >= 7) {
  osIdReal = osIdTrigger;
} else {
  return [{ json: { error: `VANDA: os_id '${trigger.os_id}' parece ser o código visível da OS, não o ID interno. O ID interno tem 7+ dígitos. Chame 'buscarContexto' para recuperar o os_id correto.` } }];
}

// Pegar hora_entrada/saida do Supabase se não vieram no trigger
const horaEntrada = trigger.hora_entrada || supabase.hora_entrada || null;
const horaSaida = trigger.hora_saida || supabase.hora_saida || null;

return [{ json: {
  ...trigger,
  os_id: osIdReal,
  os_codigo: trigger.os_codigo || supabase.os_codigo,
  hora_entrada: horaEntrada,
  hora_saida: horaSaida,
  produtos_json_supabase: supabase.produtos_json,
  servicos_json_supabase: supabase.servicos_json
} }];

const triggerParams = $('Resolver OS ID').first().json;
const osResp = $input.first().json;

if (triggerParams.error) {
  return [{ json: { error: triggerParams.error } }];
}

if (!osResp || osResp.status === 'error' || !osResp.data) {
  const dt = osResp ? (osResp.message || JSON.stringify(osResp)) : 'erro desconhecido';
  return [{ json: { error: 'FALHA GRAVE AO BUSCAR OS. Erro API: ' + dt } }];
}

const osAtual = osResp.data;

let produtos = [];
let servicos = [];
try { produtos = typeof triggerParams.produtos_json === 'string' ? JSON.parse(triggerParams.produtos_json) : (triggerParams.produtos_json || []); } catch(e) {}
try { servicos = typeof triggerParams.servicos_json === 'string' ? JSON.parse(triggerParams.servicos_json) : (triggerParams.servicos_json || []); } catch(e) {}

const emGarantia = triggerParams.em_garantia === 'true' || triggerParams.em_garantia === true;

// ── Timestamps de chegada e saída ──
let tempoMin = null;
let checkinBR = null;
let checkoutBR = null;

const parseTimeStr = (tStr) => {
  if (!tStr) return null;
  if (String(tStr).includes('T')) {
    try {
      const d = new Date(tStr);
      if (!isNaN(d)) return { ms: d.getTime(), str: d.toLocaleTimeString('pt-BR', {hour: '2-digit', minute:'2-digit'}) };
    } catch {}
  }
  const match = String(tStr).match(/([0-9]{1,2}):([0-9]{2})/);
  if (match) {
    const h = parseInt(match[1]);
    const m = parseInt(match[2]);
    return { ms: (h * 60 + m) * 60000, str: `${String(h).padStart(2,'0')}:${String(m).padStart(2,'0')}` };
  }
  return null;
}

if (triggerParams.hora_entrada && triggerParams.hora_saida) {
  const p1 = parseTimeStr(triggerParams.hora_entrada);
  const p2 = parseTimeStr(triggerParams.hora_saida);

  if (p1) checkinBR = p1.str;
  if (p2) checkoutBR = p2.str;

  if (p1 && p2) {
    let diff = Math.round((p2.ms - p1.ms) / 60000);
    if (diff < 0) diff += 24 * 60; // crossed midnight
    tempoMin = diff;
  }
} else {
  if (triggerParams.hora_entrada) {
     const p1 = parseTimeStr(triggerParams.hora_entrada);
     if (p1) checkinBR = p1.str;
  }
  if (triggerParams.hora_saida) {
     const p2 = parseTimeStr(triggerParams.hora_saida);
     if (p2) checkoutBR = p2.str;
  }
}

// Relatório técnico + timestamps
let obsInterna = triggerParams.relatorio_tecnico || triggerParams.laudo || osAtual.observacoes_interna || '';

const tsLinhas = [];
if (checkinBR && !obsInterna.includes('[CHEGADA:')) tsLinhas.push(`[CHEGADA: ${checkinBR}]`);
if (checkoutBR && !obsInterna.includes('[SAÍDA:') && !obsInterna.includes('[SAIDA:')) tsLinhas.push(`[SAÍDA: ${checkoutBR}]`);
if (tempoMin !== null && !obsInterna.includes('[TEMPO:')) tsLinhas.push(`[TEMPO: ${tempoMin} min]`);
if (tsLinhas.length > 0) {
  obsInterna = (obsInterna ? obsInterna + '\n' : '') + tsLinhas.join('\n');
}

const payload = {
  codigo: osAtual.codigo,
  cliente_id: osAtual.cliente_id,
  data: osAtual.data || new Date().toISOString().split('T')[0],
  observacoes: triggerParams.observacoes_orientacao || osAtual.observacoes || '',
  observacoes_interna: obsInterna.trim(),
  situacao_id: String(triggerParams.situacao_id || '6237499')
};

// Equipamentos
let equipamentosArray = osAtual.equipamentos || [];
if (triggerParams.equipamento) {
  equipamentosArray = [{
    equipamento: {
      equipamento: triggerParams.equipamento || '',
      marca: triggerParams.marca || '',
      modelo: triggerParams.modelo || '',
      defeitos: triggerParams.defeito || '',
      solucao: triggerParams.solucao || '',
      laudo: triggerParams.relatorio_tecnico || triggerParams.laudo || ''
    }
  }];
}
if (equipamentosArray.length > 0) payload.equipamentos = equipamentosArray;

// Produtos (manter existentes + novos)
let produtosArray = [];
if (osAtual.produtos) {
  osAtual.produtos
    .filter(p => p.produto.produto_id && p.produto.produto_id !== '')
    .forEach(p => {
      produtosArray.push({ produto: {
        produto_id: p.produto.produto_id,
        variacao_id: p.produto.variacao_id,
        quantidade: String(p.produto.quantidade),
        valor_venda: emGarantia ? '0' : String(p.produto.valor_venda),
        tipo_desconto: p.produto.tipo_desconto || 'R$',
        desconto_valor: String(p.produto.desconto_valor || '0'),
        desconto_porcentagem: String(p.produto.desconto_porcentagem || '0')
      }});
    });
}
produtos.forEach(p => {
  const pid = p.produto_id || p.id || p.ID || p.codigo;
  if (!pid || pid === '') return;
  produtosArray.push({ produto: {
    produto_id: pid,
    variacao_id: p.variacao_id || '',
    quantidade: String(p.quantidade || '1'),
    valor_venda: emGarantia ? '0' : String(p.valor_venda ?? '0'),
    tipo_desconto: 'R$', desconto_valor: '0', desconto_porcentagem: '0'
  }});
});
if (produtosArray.length > 0) payload.produtos = produtosArray;

// Serviços (manter existentes + novos)
let servicosArray = [];
if (osAtual.servicos) {
  osAtual.servicos
    .filter(s => s.servico.servico_id && s.servico.servico_id !== '')
    .forEach(s => {
      servicosArray.push({ servico: {
        servico_id: s.servico.servico_id,
        quantidade: String(s.servico.quantidade),
        valor_venda: emGarantia ? '0' : String(s.servico.valor_venda),
        tipo_desconto: s.servico.tipo_desconto || 'R$',
        desconto_valor: String(s.servico.desconto_valor || '0'),
        desconto_porcentagem: String(s.servico.desconto_porcentagem || '0')
      }});
    });
}
servicos.forEach(s => {
  const sid = s.servico_id || s.id || s.ID || s.codigo;
  if (!sid || sid === '') return;
  servicosArray.push({ servico: {
    servico_id: sid,
    quantidade: String(s.quantidade || '1'),
    valor_venda: emGarantia ? '0' : String(s.valor_venda ?? '0'),
    tipo_desconto: 'R$', desconto_valor: '0', desconto_porcentagem: '0'
  }});
});
if (servicosArray.length > 0) payload.servicos = servicosArray;

// Atributos OS
const camposExtras = [];
if (triggerParams.observacoes_orientacao) {
  camposExtras.push({ atributo_os: { atributo_id: '58530', valor: triggerParams.observacoes_orientacao } });
}
if (triggerParams.relatorio_tecnico || triggerParams.laudo) {
  camposExtras.push({ atributo_os: { atributo_id: '58528', valor: triggerParams.relatorio_tecnico || triggerParams.laudo } });
}
const tipoServico = emGarantia ? 'Garantia' : (triggerParams.tipo_servico || '');
if (tipoServico) {
  camposExtras.push({ atributo_os: { atributo_id: '58529', valor: tipoServico } });
}
if (camposExtras.length > 0) payload.atributos_os = camposExtras;

// Garantia — pagamento zerado
if (emGarantia) {
  payload.pagamentos = [{ pagamento: { data_vencimento: new Date().toISOString().split('T')[0], valor: '0.00', forma_pagamento_id: '4366641' } }];
  // Extract hora entrada e saida 
return [{ json: { 
  hora_entrada: triggerParams.hora_entrada || supRow.hora_entrada || '',
  hora_saida: triggerParams.hora_saida || supRow.hora_saida || '',
  os_id: triggerParams.os_id, os_codigo: triggerParams.os_codigo, payload, tempo_atendimento_min: tempoMin } }];
}

// Calcular total
let sumTotal = 0;
produtosArray.forEach(p => {
  sumTotal += parseFloat(p.produto.quantidade || 0) * parseFloat(p.produto.valor_venda || 0);
});
servicosArray.forEach(s => {
  sumTotal += parseFloat(s.servico.quantidade || 0) * parseFloat(s.servico.valor_venda || 0);
});

// Forma de pagamento
let formaId = '4366641';
const tp = (triggerParams.tipo_pagamento || '').toLowerCase();
if (tp.includes('pix') && (tp.includes('nubank') || (!tp.includes('inter') && !tp.includes('cora')))) formaId = '4366643';
else if (tp.includes('pix') && tp.includes('inter')) formaId = '4377571';
else if (tp.includes('pix') && tp.includes('cora')) formaId = '4384234';
else if (tp.includes('dinheiro') || tp.includes('especie') || tp.includes('espécie')) formaId = '4354377';
else if (tp.includes('boleto') || tp.includes('faturad') || tp.includes('escritorio')) formaId = '4366641';
else if (osAtual.pagamentos?.length > 0) formaId = osAtual.pagamentos[0].pagamento.forma_pagamento_id || formaId;

payload.pagamentos = [{ pagamento: {
  data_vencimento: new Date().toISOString().split('T')[0],
  valor: String(Math.max(sumTotal, 0).toFixed(2)),
  forma_pagamento_id: formaId
}}];

return [{ json: { os_id: triggerParams.os_id, os_codigo: triggerParams.os_codigo, payload, tempo_atendimento_min: tempoMin } }];

const payloadJson = $('Montar Payload').first().json;
if (payloadJson.error) {
  return [{ json: { sucesso: false, resultado: payloadJson.error } }];
}

const data = $('PUT Atualizar OS').first().json;
if (data.status === 'error' || data.error || data.message || (data.statusCode && data.statusCode >= 400)) {
  const detalheErro = data.message || data.error || JSON.stringify(data);
  return [{ json: { sucesso: false, resultado: 'Erro fatal ao SALVAR a OS. Detalhes: ' + detalheErro } }];
}
return [{ json: { sucesso: true, resultado: 'OS #' + (payloadJson.os_codigo || '') + ' Atualizada/Fechada com SUCESSO!', dados: data.data || data } }];
